import sys

class Solution:
    def solve(self, s: str, k: int) -> int:
        def at_most(k_dist: int) -> int:
            if k_dist < 0:
                return 0
            count = {}
            left = 0
            res = 0
            distinct = 0
            for right, ch in enumerate(s):
                if count.get(ch, 0) == 0:
                    distinct += 1
                count[ch] = count.get(ch, 0) + 1
                while distinct > k_dist:
                    left_ch = s[left]
                    count[left_ch] -= 1
                    if count[left_ch] == 0:
                        distinct -= 1
                    left += 1
                res += right - left + 1
            return res
        return at_most(k) - at_most(k - 1)

if __name__ == "__main__":
