#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int atMost(const string &s, int k) {
        if (k < 0) return 0;
        unordered_map<char,int> cnt;
        int left = 0, distinct = 0;
        long long res = 0;
        for (int right = 0; right < (int)s.size(); ++right) {
            char ch = s[right];
            if (cnt[ch] == 0) distinct++;
            cnt[ch]++;
            while (distinct > k) {
                char lc = s[left++];
                cnt[lc]--;
                if (cnt[lc] == 0) distinct--;
            }
            res += right - left + 1;
        }
        return (int)res;
    }
    int solve(string &s, int k) {
        return atMost(s, k) - atMost(s, k-1);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    if(!(cin >> s)) return 0;
    int k;
    if(!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.solve(s, k);
    cout << ans << "\n";
    return 0;
}
